from fastapi import APIRouter, HTTPExceptionfrom models.app_models import UserQuery, IntentDomain, ChatResponseType, ChatResponse, \    FormUpdateIntent, FormResponse, FormSubmissionRequestfrom services.browser_use_service import BrowserUseServicefrom services.redis_service import redis_servicefrom services.session_service import session_serviceagent_router = APIRouter(prefix="/agent", tags=["Agent"])browser_use_service = BrowserUseService()@agent_router.post("/chat")async def chat(request: UserQuery) -> ChatResponse:    agent = session_service.get_session_agent(request.session_id)    if agent is None:        raise HTTPException(404, "Chat session not found. Create a message session first.")    chat_state = await redis_service.get_chat_messages(request.session_id)    parsed_intent = await browser_use_service.infer_user_intent(request, chat_state)    if parsed_intent.domain == IntentDomain.APP and (app_intent := parsed_intent.intent):        return ChatResponse(response_type=ChatResponseType.APP_INTENT, response=app_intent)    if parsed_intent.domain == IntentDomain.FORM and (form_intent := parsed_intent.intent):        await redis_service.set_chat_message(request.session_id, form_intent.form_reference_id)        return ChatResponse(response_type=ChatResponseType.FORM_UPDATE_RESPONSE, response=form_intent)    ui_state = await browser_use_service.perform_action(request, chat_state, parsed_intent, agent)    await redis_service.set_chat_message(request.session_id, ui_state)    return ChatResponse(response_type=ChatResponseType.UI_RESPONSE, response=ui_state)@agent_router.post("/submit-form")async def submit_form(request: FormSubmissionRequest):    session_id = request.form_reference_id    # Fetch form element    form_element = await redis_service.get_chat_message(session_id)    form_element = FormResponse.model_validate(form_element)    await redis_service.set_chat_message(session_id, form_element)    # Submit form    session_id = request.session_id    form_element = await redis_service.get_chat_message(session_id)    agent = session_service.get_session_agent(session_id)    if not agent or not form_element:        raise HTTPException(404, "Chat session not found. Create a message session first.")    await browser_use_service.submit_form(form_element, agent)